class SystemAdminService {
  
  private val allowedCommands = Set(
    "ls", "ps", "df", "du", "top", "free", "uptime", "whoami",
    "cat", "grep", "awk", "sed", "find", "tail", "head",
    "systemctl", "journalctl", "docker", "kubectl", "git",
