      request.timeout match {
        case Some(timeoutMs) => executeWithTimeout(processBuilder, timeoutMs)
        case None => executeProcess(processBuilder)
      }
    }
  }

  def executeSimpleCommand(command: String, userInput: String): Try[CommandResult] = {
    Try {
      val sanitizedInput = sanitizeInput(userInput)
      val fullCommand = s"$command $sanitizedInput"
      
      validateCommand(command)
      
