      val exitCode = fullCommand.!(logger)
      
      CommandResult(
        exitCode = exitCode,
        stdout = stdout.toString.trim,
        stderr = stderr.toString.trim,
        success = exitCode == 0
      )
    }
  }

  def executeShellCommand(userInput: String): Try[CommandResult] = {
