  def executePipedCommand(commands: List[String]): Try[CommandResult] = {
    Try {
      commands.foreach(cmd => validateCommand(cmd.split("\\s+").head))
      
      val sanitizedCommands = commands.map(sanitizeInput)
      
      val processes = sanitizedCommands.map(cmd => Process(cmd))
      val pipedProcess = processes.reduce(_ #| _)
      
      val stdout = new StringBuilder
      val stderr = new StringBuilder
      
      val logger = ProcessLogger(
        out => stdout.append(out).append("\n"),
        err => stderr.append(err).append("\n")
