      val sanitizedOutputFile = sanitizeInput(outputFile)
      
      val process = Process(command :: sanitizedArgs)
      val output = new File(sanitizedOutputFile)
      
      val redirectedProcess = process #> output
      
      val stderr = new StringBuilder
      val logger = ProcessLogger(_ => (), err => stderr.append(err).append("\n"))
      
      val exitCode = redirectedProcess.!(logger)
      
      CommandResult(
        exitCode = exitCode,
        stdout = s"Output written to $sanitizedOutputFile",
        stderr = stderr.toString.trim,
        success = exitCode == 0
      )
    }
