  private def buildProcess(
    command: String,
    args: List[String],
    workingDir: Option[String],
    env: Map[String, String]
  ): ProcessBuilder = {
    val baseProcess = Process(command :: args, workingDir.map(new File(_)), env.toSeq: _*)
    baseProcess
  }

  private def executeProcess(processBuilder: ProcessBuilder): CommandResult = {
    val stdout = new StringBuilder
    val stderr = new StringBuilder
    
    val logger = ProcessLogger(
      out => stdout.append(out).append("\n"),
      err => stderr.append(err).append("\n")
    )
    
    val exitCode = processBuilder.!(logger)
    
    CommandResult(
      exitCode = exitCode,
      stdout = stdout.toString.trim,
      stderr = stderr.toString.trim,
      success = exitCode == 0
    )
  }

  private def executeWithTimeout(processBuilder: ProcessBuilder, timeoutMs: Long): CommandResult = {
    val stdout = new StringBuilder
    val stderr = new StringBuilder
    
    val logger = ProcessLogger(
      out => stdout.append(out).append("\n"),
      err => stderr.append(err).append("\n")
    )
    
    val process = processBuilder.run(logger)
    
    val completed = process.exitValue() match {
      case _ if waitForProcess(process, timeoutMs) => true
      case _ =>
        process.destroy()
        false
    }
    
    if (completed) {
      CommandResult(
        exitCode = process.exitValue(),
        stdout = stdout.toString.trim,
        stderr = stderr.toString.trim,
        success = process.exitValue() == 0
      )
    } else {
      CommandResult(
        exitCode = -1,
        stdout = stdout.toString.trim,
        stderr = s"Command timed out after ${timeoutMs}ms\n${stderr.toString.trim}",
        success = false
      )
    }
  }

  private def waitForProcess(process: Process, timeoutMs: Long): Boolean = {
    val startTime = System.currentTimeMillis()
    while (process.isAlive() && (System.currentTimeMillis() - startTime) < timeoutMs) {
      Thread.sleep(100)
    }
    !process.isAlive()
  }

  private def validateCommand(command: String): Unit = {
    val baseCommand = command.split("\\s+").head
    if (!allowedCommands.contains(baseCommand)) {
      throw new SecurityException(s"Command not allowed: $baseCommand")
    }
  }

  private def sanitizeInput(input: String): String = {
