class DevOpsAutomationAPI {
  private val service = new SystemAdminService()

  def listFiles(directory: String): Try[CommandResult] = {
    service.executeCommand(CommandRequest("ls", List("-la", directory)))
  }

  def checkDiskUsage(path: String): Try[CommandResult] = {
    service.executeCommand(CommandRequest("df", List("-h", path)))
  }

  def searchFiles(pattern: String, directory: String): Try[CommandResult] = {
    service.executeCommand(CommandRequest("find", List(directory, "-name", pattern)))
  }

  def viewLogs(logFile: String, lines: Int): Try[CommandResult] = {
    service.executeCommand(CommandRequest("tail", List("-n", lines.toString, logFile)))
  }

  def processStatus(processName: String): Try[CommandResult] = {
    service.executePipedCommand(List(s"ps aux", s"grep $processName"))
  }

  def dockerStatus(containerName: String): Try[CommandResult] = {
    service.executeCommand(CommandRequest("docker", List("ps", "-a", "--filter", s"name=$containerName")))
  }

  def systemctlStatus(serviceName: String): Try[CommandResult] = {
    service.executeCommand(CommandRequest("systemctl", List("status", serviceName)))
  }

  def gitPull(repoPath: String): Try[CommandResult] = {
    service.executeCommand(CommandRequest("git", List("pull"), Some(repoPath)))
  }

  def customCommand(command: String, userInput: String): Try[CommandResult] = {
    service.executeSimpleCommand(command, userInput)
  }

  def runScript(scriptPath: String, args: List[String]): Try[CommandResult] = {
    service.executeCommand(CommandRequest("sh", scriptPath :: args))
  }
}

